typedef enum _WDMUSB_POWER_STATE {
  WdmUsbPowerNotMapped = 0,
  WdmUsbPowerSystemWorking,
  WdmUsbPowerSystemSleeping1,
  WdmUsbPowerSystemSleeping2,
  WdmUsbPowerSystemSleeping3,
  WdmUsbPowerSystemHibernate,
  WdmUsbPowerSystemShutdown
} WDMUSB_POWER_STATE;

typedef struct _USB_BANDWIDTH_INFO {   ULONG DeviceCount;
ULONG TotalBusBandwidth;   ULONG Total32secBandwidth;
ULONG AllocedBulkAndControl;   ULONG AllocedIso;
ULONG AllocedInterrupt_1ms;   ULONG AllocedInterrupt_2ms;   ULONG AllocedInterrupt_4ms;   ULONG AllocedInterrupt_8ms;   ULONG AllocedInterrupt_16ms;   ULONG AllocedInterrupt_32ms;
} USB_BANDWIDTH_INFO, *PUSB_BANDWIDTH_INFO;

typedef struct _USB_BUS_STATISTICS_0 {
    ULONG DeviceCount;
    // Additional members would be listed here
} USB_BUS_STATISTICS_0;

typedef struct _USB_CLOSE_RAW_DEVICE_PARAMETERS {
    ULONG Reserved;
} USB_CLOSE_RAW_DEVice_PARAMETERS, *PUSB_CLOSE_RAW_DEVICE_PARAMETERS;

typedef struct _USB_CONTROLLER_INFO_0 {
ULONG                 PciVendorId;   ULONG                 PciDeviceId;   ULONG                 PciRevision;
ULONG                 NumberOfRootPorts;   USB_CONTROLLER_FLAVOR ControllerFlavor;   ULONG                 HcFeatureFlags;
} USB_CONTROLLER_INFO_0, *PUSB_CONTROLLER_INFO_0;

typedef struct _USB_DRIVER_VERSION_PARAMETERS {
  ULONG DriverTrackingCode;
  ULONG USBDI_Version;
  ULONG USBUSER_Version;
  BOOLEAN CheckedPortDriver;
  BOOLEAN CheckedMiniportDriver;
  USHORT USB_Version;
} USB_DRIVER_VERSION_PARAMETERS, *PUSB_DRIVER_VERSION_PARAMETERS;

typedef struct _USB_PASS_THRU_PARAMETERS {   GUID  FunctionGUID;
ULONG ParameterLength;   UCHAR Parameters[4];
} USB_PASS_THRU_PARAMETERS, *PUSB_PASS_THRU_PARAMETERS;

typedef struct _USB_POWER_INFO {
  WDMUSB_POWER_STATE SystemState;
  // other members
} USB_POWER_INFO, *PUSB_POWER_INFO;

typedef struct _USB_UNICODE_NAME {   ULONG Length;
WCHAR String[1];
} USB_UNICODE_NAME, *PUSB_UNICODE_NAME;

typedef struct _USBUSER_REQUEST_HEADER {
  ULONG UsbUserRequest;
  ULONG UsbUserBufferLength;
} USBUSER_REQUEST_HEADER;

typedef struct _WINUSB_PIPE_INFORMATION {
  USBD_PIPE_TYPE PipeType;
  UCHAR PipeId;
  USHORT MaximumPacketSize;
  UCHAR Interval;
} WINUSB_PIPE_INFORMATION;

typedef struct _WINUSB_PIPE_INFORMATION_EX {
  USBD_PIPE_TYPE PipeType;
  UCHAR PipeId;
  USHORT MaximumPacketSize;
  ULONG PipeFlags;
} WINUSB_PIPE_INFORMATION_EX;

typedef struct _WINUSB_SETUP_PACKET {
  UCHAR RequestType;
  UCHAR Request;
  USHORT Value;
  USHORT Index;
  USHORT Length;
} WINUSB_SETUP_PACKET, *PWINUSB_SETUP_PACKET;
